<template><ModulePageShell title="不良事件统计" description="从结构化术中事件与术后事件读取真实质控证据"><template #chips><a-tag color="red">事件 {{result.total}}</a-tag></template><template #toolbar><a-button :loading="loading" @click="reload">刷新</a-button></template><a-alert v-if="error" type="error" show-icon>{{error}}</a-alert><a-empty v-else-if="!loading&&!result.total" description="当前范围无不良事件"/><a-card v-else class="section-card" :bordered="false" title="不良事件列表"><a-table :data="result.list" row-key="id" :pagination="{pageSize:10}"><template #columns><a-table-column title="事件" data-index="type"/><a-table-column title="患者" data-index="patientName"/><a-table-column title="阶段" data-index="stage"/><a-table-column title="严重度" data-index="severity"/><a-table-column title="发生时间" data-index="eventTime"/><a-table-column title="处置" data-index="treatment"/><a-table-column title="审核" data-index="reviewStatus"/><a-table-column title="操作"><template #cell="{record}"><a-link @click="router.push(`/surgery/detail/${record.caseId}`)">病例穿透</a-link></template></a-table-column></template></a-table></a-card></ModulePageShell></template>
<script setup lang="ts">import{onMounted,reactive,ref}from'vue';import{useRouter}from'vue-router';import ModulePageShell from'@/components/shared/ModulePageShell.vue';import{qualityApi,type QualityAdverseEventResultApi}from'@/api/quality';const router=useRouter(),loading=ref(false),error=ref(''),result=reactive<QualityAdverseEventResultApi>({total:0,list:[]});async function reload(){loading.value=true;error.value='';try{Object.assign(result,await qualityApi.getAdverseEvents());}catch(e){Object.assign(result,{total:0,list:[]});error.value=`加载失败：${(e as Error).message}`;}finally{loading.value=false;}}onMounted(reload);</script>
